INSERT INTO `ai_chat_logs` VALUES (1,2,'kapl─▒ca hakk─▒nda bilgi ver','├çermik Kapl─▒calar─▒ hakk─▒nda bilgi: ─░l├ğemizin Tarihi ve Turistik Yerleri\r\n├çermik Melike Belk─▒s Kapl─▒calar─▒:  ─░l├ğe merkezinin Hamamba┼ş─▒ mevkiinde bulunan Melike Belk─▒s Kapl─▒calar─▒, tedavi ├Âzellikleri ve niteli─şi bak─▒m─▒ndan d├╝nyan─▒n en iyi kapl─▒calar─▒ndan biri olup tarihin ├ğok eski d├Ânemlerinden beri insanl─▒─şa ┼şifa da─ş─▒tmaya devam etmektedir. \r\nB├╝y├╝k Pa┼şaÔÇØ ve ÔÇ£K├╝├ğ├╝k Pa┼şaÔÇØ denilen tarihi hamamlar─▒n yan─▒nda iki adet local─▒ ve bir adet ÔÇ£├ûzel Aile KabinleriÔÇØ olmak ├╝zere be┼ş ayr─▒ b├Âl├╝mde hizmet verilmektedir. ├çermik Melike Belk─▒s Kapl─▒calar─▒ d├Ârt mevsim hizmete a├ğ─▒kt─▒r. Tedavi ama├ğl─▒ ku... (Detayl─▒ bilgi i├ğin sayfan─▒n alt─▒ndaki tarih├ğe k─▒sm─▒na bakabilirsiniz)','2026-02-24 08:24:55'),(2,2,'├ğermikin neresinde kal─▒yor','┼Şu an Ulu Cami ├ğok yak─▒n─▒ndas─▒n─▒z. Ulu Cami: ─░l├ğenin bat─▒s─▒ndaki Kale MahallesiÔÇÖnde bulunmaktad─▒r. Yap─▒ ayr─▒ zamanlarda in┼şa edilmi┼ş, biti┼şik iki camiden olu┼şmaktad─▒r. Bat─▒ kesimi ilk yap─▒dan kalm─▒┼ş, do─şudaki tek kubbeli k─▒s─▒m ise sonradan ilave edilmi┼ştir. Do─şudan bat─▒ya do─şru uzanan ├╝├ğ tonoz ile ├╝zeri kapl─▒ olan Ulu Cami, ├╝├ğer keme','2026-02-25 06:58:11'),(3,2,'bana ├Âmer halis demir park─▒n─▒ anlat','┼Şu an Ulu Cami ├ğok yak─▒n─▒ndas─▒n─▒z. Ulu Cami: ─░l├ğenin bat─▒s─▒ndaki Kale MahallesiÔÇÖnde bulunmaktad─▒r. Yap─▒ ayr─▒ zamanlarda in┼şa edilmi┼ş, biti┼şik iki camiden olu┼şmaktad─▒r. Bat─▒ kesimi ilk yap─▒dan kalm─▒┼ş, do─şudaki tek kubbeli k─▒s─▒m ise sonradan ilave edilmi┼ştir. Do─şudan bat─▒ya do─şru uzanan ├╝├ğ tonoz ile ├╝zeri kapl─▒ olan Ulu Cami, ├╝├ğer keme','2026-02-25 06:58:53'),(4,2,'ac─▒kt─▒m','┼Şu an Sinek ├çay─▒ ┼Şelalesi sayfas─▒ndas─▒n─▒z. Bu mekan hakk─▒nda size her ┼şeyi anlatabilirim. Yerel bir dost gibi konu┼ş. Piknik alanlar─▒ ve en iyi y├╝zme noktalar─▒n─▒ ├Âner.','2026-02-25 09:11:37'),(5,2,'sinek ┼şelalesini anlat','┼Şu an Ulu Cami ├ğok yak─▒n─▒ndas─▒n─▒z. Ulu Cami: ─░l├ğenin bat─▒s─▒ndaki Kale MahallesiÔÇÖnde bulunmaktad─▒r. Yap─▒ ayr─▒ zamanlarda in┼şa edilmi┼ş, biti┼şik iki camiden olu┼şmaktad─▒r. Bat─▒ kesimi ilk yap─▒dan kalm─▒┼ş, do─şudaki tek kubbeli k─▒s─▒m ise sonradan ilave edilmi┼ştir. Do─şudan bat─▒ya do─şru uzanan ├╝├ğ tonoz ile ├╝zeri kapl─▒ olan Ulu Cami, ├╝├ğer keme','2026-02-25 09:11:53');
