INSERT INTO `hospitals` VALUES (1,'├çermik Devlet Hastanesi','Genel Kapasite ve Yeni Hizmet Binas─▒\r\nYeni Hastane Binas─▒: Hastane, A─şustos 2024\'te 18.810 metrekarelik kapal─▒ alana sahip yeni ve modern binas─▒na ta┼ş─▒narak 50 yatak kapasitesiyle hizmet vermeye ba┼şlam─▒┼şt─▒r. Eski binas─▒ndan ta┼ş─▒nd─▒─ş─▒ i├ğin g├╝ncel adresi de─şi┼şmi┼ştir.\r\n\r\nKapasite Detaylar─▒: 25 poliklinik odas─▒, 3 ameliyathane, 20\'si tek ki┼şilik ve 15\'i ├ğift ki┼şilik olmak ├╝zere toplam 35 hasta odas─▒ ile hasta kabul etmektedir.\r\n\r\nYo─şun Bak─▒m ve ├£niteler: 4 yatakl─▒ yenido─şan yo─şun bak─▒m, 6 yatakl─▒ genel yo─şun bak─▒m, 7 cihazl─▒ hemodiyaliz ├╝nitesi ve 10 hasta kapasiteli fizik tedavi ├╝nitesi mevcuttur.\r\n\r\n2026 Y─▒l─▒ndaki ├ûnemli Geli┼şmeler\r\nAnne Dostu Hastane Unvan─▒ (Ocak 2026): Hastane, Sa─şl─▒k Bakanl─▒─ş─▒ taraf─▒ndan yap─▒lan de─şerlendirmeler sonucunda anne ve bebek sa─şl─▒─ş─▒n─▒ ├Ânceleyen standartlar─▒ ba┼şar─▒yla kar┼ş─▒layarak \"Anne Dostu Hastane\" unvan─▒n─▒ ald─▒. ├çermik Devlet Hastanesi, 2026 y─▒l─▒nda T├╝rkiye genelinde bu unvan─▒ almaya hak kazanan ilk sa─şl─▒k tesisi oldu.\r\n\r\nBa┼şhekim De─şi┼şikli─şi (┼Şubat 2026): ┼Şubat 2026 ba┼şlar─▒nda hastane ba┼şhekimli─şine Umut Karag├Âz\'├╝n yerine F─▒rat T├╝rken atanm─▒┼şt─▒r.\r\n\r\n├ûne ├ç─▒kan Hizmetler ve Donan─▒mlar\r\nHastane, yenido─şan sar─▒l─▒─ş─▒ tedavisini h─▒zland─▒ran t├╝nel fototerapi cihazlar─▒ ve mide/ba─ş─▒rsak hastal─▒klar─▒n─▒n te┼şhisi i├ğin kurulan endoskopi/kolonoskopi ├╝niteleriyle b├Âlge halk─▒na geli┼şmi┼ş t─▒bbi imkanlar sunmaktad─▒r.\r\n\r\n5 yatak kapasiteli evde sa─şl─▒k hizmeti birimi de aktif olarak b├Âlge halk─▒na destek vermektedir.\r\n\r\nG├╝ncel ─░leti┼şim ve Adres Bilgileri\r\n(├ûnemli Not: Eski \"Siverek Yolu\" adresi yeni binayla birlikte de─şi┼şmi┼ştir.)\r\n\r\nAdres: Tepe Mahallesi, Diyarbak─▒r Caddesi No:128 ├çermik / Diyarbak─▒r\r\n\r\nTelefon: 0 (412) 606 05 74\r\n\r\nE-posta: dbkrcermikdh.bsh@saglik.gov.tr',38.14381625,39.47553181,'','uploads/hospital_1772196367.jpeg','2026-02-23 08:43:00','',''),(2,'├çermik 1 Nolu Sa─şl─▒k Oca─ş─▒','',38.13589309,39.45398365,'','','2026-02-23 08:51:44',NULL,NULL),(3,'├çermik 2 Nolu Sa─şl─▒k Oca─ş─▒','',38.13757291,39.46782466,'','','2026-02-23 08:51:55',NULL,NULL),(4,'├çermik 3 Nolu Sa─şl─▒k Oca─ş─▒','',38.13485516,39.44729905,'','','2026-02-24 09:24:23',NULL,NULL);
