INSERT INTO `services` VALUES (5,'├çermik Belediyesi Melike Belk─▒s Kapl─▒calar─▒n─▒ Yenileyerek Modern Hale Getirdik.','2016 YILINDA H─░ZMETE GELD─░─Ş─░M─░Z G├£NDEN ─░T─░BAREN ESK─░ HALDE OLAN KAPLICALARIMIZI MODERN HALE GET─░REREK HALKMIZIN H─░ZMET─░NE SUNDUK.\r\n\r\n',1,'uploads/projects/1772008365_saat kulesi.jpg',NULL,NULL),(6,'Do─şalgaz ','┼Şimdiye kadar k├Âm├╝r ve di─şer kat─▒ at─▒klar ile il├ğemiz halk─▒n─▒n ─▒s─▒nma ve di─şer ticari faaliyet alanlar─▒nda kulland─▒─ş─▒ k├Ât├╝ koku ve hava kirlili─şine neden olan yak─▒t t├╝rlerini son vermek i├ğin enerji ve tabii kaynaklar bakanl─▒─ş─▒ ile yapm─▒┼ş oldu─şumuz g├Âr├╝┼şmeler neticesinde halk─▒m─▒za s├Âz verdi─şimiz gibi do─şal gaz alt yap─▒ hizmetlerini tamamlayarak il├ğe halk─▒m─▒z─▒n hizmetine sunduk.',1,'uploads/projects/1772011283_WhatsApp Image 2019-03-19 at 15.54.38.jpeg',NULL,NULL),(7,'─░├ğme Suyu','─░l├ğe merkezimizde 50 y─▒l─▒ a┼şk─▒n s├╝redir kullan─▒m─▒ ger├ğekle┼ştirilen sa─şl─▒ks─▒z aspes borular ile hane ve i┼ş yerlerine giden i├ğme suyu ┼şebekemizin alt yap─▒s─▒n─▒n tamam─▒n─▒ Diyarbak─▒r B├╝y├╝k┼şehir Belediyesine ba─şl─▒ D─░SK─░ genel M├╝d├╝rl├╝─ş├╝ ile yap─▒lan mutabakatlar sonucunda i├ğme suyu ┼şebekesini yenileterek halk─▒m─▒z─▒n hizmetine sunduk.\r\n\r\n',1,'uploads/projects/1772011493_hikaye kapak.jpg',NULL,NULL),(8,'Hizmet Binas─▒','1960 y─▒l─▒ndan bu yana bir ├ğok belediye ba┼şkan─▒ taraf─▒ndan kullan─▒lan g├╝n├╝m├╝z ┼şartlar─▒ndan halk─▒m─▒za hizmet konusunda eksik kalan hizmet binam─▒z─▒ daha modern hale getirerek yeniledik.\r\n\r\n',1,'',NULL,NULL),(9,'Sokak Sa─şl─▒kla┼şt─▒rma','─░l├ğemizin Merkez tarihi ├ğar┼ş─▒s─▒nda hizmet veren i┼şyerlerinin g├Âr├╝nt├╝ kirli─şi olu┼şturdu─şu bu do─şrultuda daha modern hizmet verecek i┼ş yerleri haline getirerek Diyarbak─▒r B├╝y├╝k┼şehir Belediyesinin katk─▒lar─▒ ile halk─▒m─▒z esnaflar─▒ caddesinin ├ğehresini de─şi┼ştirdik.',1,'',NULL,NULL),(10,'Kuruyemi┼ş Pazar─▒','─░l├ğemizde y─▒llard─▒r hizmet veren kuruyemi┼ş Pazar esnaflar─▒ ile yap─▒lan isti┼şare sonucunda esnaf ve sanatkarlar─▒m─▒z─▒n talepleri neticesinde ├çermik Belediyesi olarak yapm─▒┼ş oldu─şumuz proje ile i┼ş yerlerini daha konforlu hale getirip esnaf ve halk─▒m─▒z─▒n hizmetine sunduk.',1,'',NULL,NULL),(11,'Hal─▒ Saha','Ba┼şta gen├ğlerimiz ve t├╝m spor severerler i├ğin yapm─▒┼ş oldu─şumuz hal─▒ saha projelerimizi spor toto ile imzalam─▒┼ş oldu─şumuz protokollerle 2 adet il├ğe Merkezimizde 10 adet K─▒rsal Mahallelerimizde olmak ├╝zere 12 adet hal─▒ sahan─▒n yap─▒m─▒n─▒ ger├ğekle┼ştirdik.',1,'',NULL,NULL),(12,'I┼ş─▒kland─▒rma','─░l├ğemiz Tepe Mahallesi Belediye hizmet binas─▒ ├Ân├╝nden Meslek y├╝ksek okulu mevkisine kadar alt yap─▒ ve ├╝st yap─▒ ├ğal─▒┼şmalar─▒n─▒ bitirmi┼ş oldu─şumuz caddemize modern cadde-sokak ayd─▒nlatmalar─▒ ile il├ğemize ayr─▒ bir hava katt─▒k.\r\n\r\n',1,'',NULL,NULL),(13,'Park ve Bah├ğeler','G├Âreve geldi─şimiz 2016 y─▒l─▒ndan yapm─▒┼ş oldu─şumuz izlenim sonucunda il├ğemizin b├╝y├╝k eksikliklerinden olan ├ğocuk oyun alan─▒ , yeti┼şkin spor alan─▒ ve ye┼şil alanlar─▒n eksikli─şi g├Âr├╝lm├╝┼şt├╝r. Bu eksikliklerin tamamlanmas─▒ i├ğin uzun y─▒llard─▒r il├ğemize k├Ât├╝ bir imaj veren kat─▒ at─▒k toplama alan─▒n─▒n yerini de─şi┼ştirerek mesire alan─▒na ├ğevirdik.Bunun akabininde il├ğemizin farkl─▒ noktalar─▒na park ve bah├ğeler kurararak , gerekli personeller ile gerek temizlik gerek g├╝venlik ├Ânlemleri alarak halk─▒m─▒z─▒n hizmetine sunduk.',1,'',NULL,NULL),(14,'TOK─░','Uzun y─▒llard─▒r talep edilip bir t├╝rl├╝ il├ğemize gelmesi hayal olan toki konutlar─▒ i├ğin d├Ânemin ├çevre ┼Şehircilik Bakan─▒ Sn.Murat KURUM ile yap─▒lan ikili g├Âr├╝┼şmeler sonucunda il├ğe merkezimizde 158 adet Toplu Konut in┼şaas─▒n─▒ il├ğemize kazand─▒rd─▒k.',1,'',NULL,NULL),(15,'K├╝lt├╝r ve Sanat','G├╝n├╝m├╝z├╝n gen├ğli─şine verdi─şimiz ├Ânem neticesinde eksiklik olarak g├Âr├╝len fuar ve etkinlik alan─▒nda ├Ânemli ├ğal─▒┼şmalar yaparak bir ├ğok etkinli─şe ├Ânc├╝l├╝k ettik. ├çermik Kitap Fuar─▒ Konser ve aktiviteler ┼Şehir gezileri',1,'',NULL,NULL),(16,'Kasaplar Sebze Pazar─▒','Kasaplar b├Âlgesi ve sebze pazar─▒n─▒n alt yap─▒ ve ├╝st yap─▒lar─▒n─▒ tamamlayarak ├╝st├╝n├╝n tamam─▒n─▒ ya─şmur g├╝ne┼ş ve olumsuz hava ┼şartlar─▒na kar┼ş─▒ kapat─▒lmas─▒n─▒ sa─şlad─▒k.',1,'',NULL,NULL),(17,'Devlet Hastanesi','─░l├ğemizde y─▒llard─▒r vatanda┼şlar─▒m─▒z─▒n kanayan yanas─▒ olan hastane ihtiyac─▒n─▒ kar┼ş─▒lamak i├ğin ├ğevre il├ğe ve illere giderek hastal─▒klar─▒na derman ar─▒yorlard─▒. Halk─▒m─▒z─▒n bu sorununun ├ğ├Âz├╝m├╝ i├ğin ─░l├ğemize yeni bir devlet hastanesi yap─▒lmas─▒ i├ğin ilgili kurumlarla yap─▒lan isti┼şareler sonucunda il├ğemize Devlet hastanesi kazand─▒rd─▒k.',1,'',NULL,NULL),(18,'Gelincik Da─ş─▒ , Drav┼şa Yolu','Gelincikda─ş─▒ , drav┼şa yolunu tamamen parke ta┼ş─▒ yaparak konumda ya┼şayan halk─▒m─▒z ve il├ğe d─▒┼ş─▒ndan turizm seyahatine gelen misafirlerimiz i├ğin ula┼ş─▒ma kolay hale getirdik.',1,'',NULL,NULL),(19,'Tarihi Saray Hamam─▒','Tarihi hamam─▒z─▒ at─▒l durumundan kurtararak yeniden restorasyon s├╝recini ba┼şlatt─▒k. Tarihi ge├ğmi┼şimize yak─▒┼ş─▒r bir hale getirdik.',1,'',NULL,NULL),(20,'Hayvan Pazar─▒ ve Mezbahane','',1,'',NULL,NULL),(21,'─░l├ğemiz giri┼şinde Siverek - Diyarbak─▒r yolu kav┼şa─ş─▒nda saat kulesi.','',1,'',NULL,NULL),(22,'Fen ve Sanat Yap─▒lar─▒','K─▒rsal mahallerimizde yollar─▒n bozulmas─▒na sebep olan dere yataklar─▒ ya─şmur sular─▒n─▒ de┼şarj edebilmek i├ğin sanat yap─▒lar─▒ ( d├╝z boru,menfez ) ├ğal─▒┼şmalar─▒ yaparak k─▒rsal mahallelerimizin sorunlar─▒n─▒ ├ğ├Âz├╝me kavu┼şturduk.',0,'',NULL,NULL),(23,'S─▒cak Asfalt ve tretuar','─░l├ğe merkezinde s─▒cak asfalt ve tretuar ├ğal─▒┼şmalar─▒ yaparak ana yollar ├╝zerindeki iklimsel sorunlar─▒ tamamen ortadan kald─▒rd─▒k.',0,'',NULL,NULL),(24,'Kamula┼şt─▒rma','Merkez mahallerimizde ara├ğlar─▒n girmekte sorun ya┼şad─▒─ş─▒ , baz─▒ b├Âlgelerde yollar─▒n tamamen t─▒kanmas─▒na sebep olan ev ve arsalar─▒ kamula┼şt─▒rma yaparak halk─▒m─▒z─▒n hizmetine sunduk.',0,'',NULL,NULL),(25,'Kilitli Parke Ta┼ş─▒','─░l├ğemiz merkezinde alt yap─▒ ve ├╝st yap─▒ ├ğal─▒┼şmalar─▒n─▒ tamamlad─▒─ş─▒m─▒z cadde ve sokaklar─▒m─▒zda kilitli parke ta┼ş─▒ d├Â┼şeyerek vatanda┼şlar─▒m─▒z─▒n hizmetine sunduk. K─▒rsal mahallelerimizin bir ├ğo─şunda g├Âr├╝len eksiklikler sonucunda kilitli parke ta┼ş─▒ yol yap─▒m i┼şlemlerimize ba┼şlad─▒k ve devam ediyoruz.',0,'',NULL,NULL);
